// CLX Email Scraper v2.2 — Prep Update Homepage
// Builds the RPC body from $input.item.json so nothing depends on
// n8n expression resolution at the HTTP node level.

const item = $input.item.json || {};

const body = {
  p_lead_id: item.id,
  p_fields: {
    email: item.email,
    email_enriched: true,
    email_enriched_at: new Date().toISOString()
  }
};

console.log('PREP UPDATE:', JSON.stringify({
  lead_id: item.id,
  email: item.email || 'none',
  path: 'homepage'
}));

return [{
  json: {
    id: item.id,
    email: item.email,
    rpc_body: JSON.stringify(body)
  }
}];

